 1→/**
 2→ * Common utility functions for Maimai Assistant web UI.
 3→ */
 4→
 5→function escapeHtml(str) {
 6→    if (!str) return '';
 7→    const div = document.createElement('div');
 8→    div.textContent = str;
 9→    return div.innerHTML;
10→}
11→
12→/**
13→ * Poll a task until it completes (fallback when WebSocket is not available).
14→ */
15→async function pollTask(taskId, onUpdate, intervalMs = 2000, maxAttempts = 300) {
16→    for (let i = 0; i < maxAttempts; i++) {
17→        try {
18→            const res = await fetch(`/api/task/${taskId}`);
19→            const data = await res.json();
20→            if (onUpdate) onUpdate(data);
21→
22→            if (data.status === 'completed' || data.status === 'failed' || data.status === 'cancelled') {
23→                return data;
24→            }
25→        } catch (e) {
26→            console.error('Poll error:', e);
27→        }
28→        await new Promise(r => setTimeout(r, intervalMs));
29→    }
30→    return null;
31→}
32→
33→/**
34→ * Format a date string for display.
35→ */
36→function formatDate(isoStr) {
37→    if (!isoStr) return '--';
38→    return new Date(isoStr).toLocaleString();
39→}
