  1→/**
  2→ * Pipeline page interaction logic.
  3→ * Handles form submission, progress tracking, candidate confirmation, and results display.
  4→ */
  5→
  6→let pipelineTaskId = null;
  7→let pipelineWS = null;
  8→let pipelineCandidates = [];
  9→
 10→document.getElementById('pipeline-form').addEventListener('submit', async (e) => {
 11→    e.preventDefault();
 12→    const form = e.target;
 13→
 14→    const keywords = form.keywords.value.split('\n').map(s => s.trim()).filter(Boolean);
 15→    const company = form.company.value.split('\n').map(s => s.trim()).filter(Boolean);
 16→    const template = form.template.value;
 17→    const pages = parseInt(form.pages.value) || 1;
 18→    const auto_send = form.auto_send.checked;
 19→    const dry_run = form.dry_run.checked;
 20→
 21→    if (!keywords.length) return alert('Please enter at least one keyword');
 22→    if (!template) return alert('Please select a template');
 23→
 24→    // Collect template variables
 25→    const variables = {};
 26→    form.querySelectorAll('[name^="var_"]').forEach(input => {
 27→        const key = input.name.replace('var_', '');
 28→        if (input.value.trim()) variables[key] = input.value.trim();
 29→    });
 30→
 31→    // Show progress, hide other sections
 32→    document.getElementById('pipeline-progress').hidden = false;
 33→    document.getElementById('pipeline-confirm').hidden = true;
 34→    document.getElementById('pipeline-results').hidden = true;
 35→    form.querySelector('button').disabled = true;
 36→
 37→    try {
 38→        const res = await fetch('/api/pipeline', {
 39→            method: 'POST',
 40→            headers: {'Content-Type': 'application/json'},
 41→            body: JSON.stringify({keywords, company, template, pages, variables, auto_send, dry_run}),
 42→        });
 43→        const data = await res.json();
 44→        pipelineTaskId = data.task_id;
 45→        document.getElementById('pipeline-task-id').textContent = data.task_id;
 46→
 47→        // Connect WebSocket for this task
 48→        pipelineWS = connectTaskWS(data.task_id, {
 49→            onEvent(msg) {
 50→                handlePipelineEvent(msg);
 51→            },
 52→            onComplete(msg) {
 53→                showPipelineResults(msg.result);
 54→                document.getElementById('pipeline-progress').hidden = true;
 55→                form.querySelector('button').disabled = false;
 56→            },
 57→            onError(msg) {
 58→                document.getElementById('pipeline-status-text').textContent = 'Failed';
 59→                document.getElementById('pipeline-detail').textContent = msg.error || 'Unknown error';
 60→                form.querySelector('button').disabled = false;
 61→            },
 62→        });
 63→
 64→        // Also start polling as fallback
 65→        pollTask(data.task_id, (task) => {
 66→            if (task.status === 'completed') {
 67→                showPipelineResults(task.result);
 68→                document.getElementById('pipeline-progress').hidden = true;
 69→                form.querySelector('button').disabled = false;
 70→                if (pipelineWS) pipelineWS.close();
 71→            }
 72→        }, 3000);
 73→
 74→    } catch (e) {
 75→        alert('Request failed: ' + e.message);
 76→        form.querySelector('button').disabled = false;
 77→        document.getElementById('pipeline-progress').hidden = true;
 78→    }
 79→});
