185→function showPipelineResults(result) {
186→    document.getElementById('pipeline-progress').hidden = true;
187→    document.getElementById('pipeline-confirm').hidden = true;
188→    document.getElementById('pipeline-results').hidden = false;
189→
190→    const summary = document.getElementById('results-summary');
191→
192→    if (!result || result.error) {
193→        summary.innerHTML = `<p>Error: ${result ? result.error : 'Unknown'}</p>`;
194→        return;
195→    }
196→
197→    if (result.dry_run) {
198→        summary.innerHTML = `
199→            <p>Dry run complete. Found <strong>${result.total}</strong> candidates.</p>
200→            <p>No messages were sent.</p>
201→        `;
202→        return;
203→    }
204→
205→    if (result.message) {
206→        summary.innerHTML = `<p>${escapeHtml(result.message)}</p>`;
207→        return;
208→    }
209→
210→    summary.innerHTML = `
211→        <div class="stat-grid">
212→            <div class="stat">
213→                <div class="value">${result.total || 0}</div>
214→                <div class="label">Total</div>
215→            </div>
216→            <div class="stat" style="color: #155724">
217→                <div class="value">${result.sent || 0}</div>
218→                <div class="label">Sent</div>
219→            </div>
220→            <div class="stat" style="color: #721c24">
221→                <div class="value">${result.failed || 0}</div>
222→                <div class="label">Failed</div>
223→            </div>
224→            <div class="stat" style="color: #856404">
225→                <div class="value">${result.skipped || 0}</div>
226→                <div class="label">Skipped</div>
227→            </div>
228→            <div class="stat" style="color: #856404">
229→                <div class="value">${result.rate_limited || 0}</div>
230→                <div class="label">Rate Limited</div>
231→            </div>
232→        </div>
233→    `;
234→}
